<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; class Club extends Model { protected $fillable=['owner_id','name','level','weekly_points','treasury']; public function members(){return $this->hasMany(ClubMember::class);} public function owner(){return $this->belongsTo(User::class,'owner_id');} public function joinRequests(){return $this->hasMany(ClubJoinRequest::class);}  }
